import{_ as e,o as r,c as t,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const m=JSON.parse('{"title":"融资额度与保证金规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/limit-and-collateral.md","filePath":"zh-CN/margin/limit-and-collateral.md"}'),i={name:"margin/limit-and-collateral.md"};function o(p,a,n,h,d,s){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="融资额度与保证金规则" tabindex="-1">融资额度与保证金规则 <a class="header-anchor" href="#融资额度与保证金规则" aria-label="Permalink to &quot;融资额度与保证金规则&quot;">​</a></h1><p>长桥账户为融资账户（保证金账户），支持杠杆交易。本文说明融资额度的评估方式、保证金计算规则及购买力逻辑。</p><h2 id="融资额度" tabindex="-1">融资额度 <a class="header-anchor" href="#融资额度" aria-label="Permalink to &quot;融资额度&quot;">​</a></h2><p>融资额度根据账户存入的现金或转仓资产自动评估，无需手动申请初始额度。</p><p>融资额度支持在 App 内按需调整，每 24 小时内最多申请 2 次（新加坡账户每 24 小时限 1 次）。操作方式参见<a href="/margin/如何关闭或降低融资额度">如何关闭或降低融资额度</a>。</p><p>结欠金额不得超过融资额度上限。</p><h2 id="保证金三层结构" tabindex="-1">保证金三层结构 <a class="header-anchor" href="#保证金三层结构" aria-label="Permalink to &quot;保证金三层结构&quot;">​</a></h2><p>账户设有三层保证金机制：</p><p>初始保证金（IM）：开仓时所需的最低保证金，决定购买力上限。</p><p>维持保证金（MM）：持仓期间需维持的最低保证金。股权资产低于此水平时发出追缴通知。</p><p>平仓保证金（FM）：强制平仓的触发线。股权资产低于此水平时可能即时强平。</p><h2 id="保证金要求计算" tabindex="-1">保证金要求计算 <a class="header-anchor" href="#保证金要求计算" aria-label="Permalink to &quot;保证金要求计算&quot;">​</a></h2><p>各层保证金要求按持仓加总计算：</p><p>保证金要求 = 加总（各持仓市值 × 对应保证金系数）</p><p>不同证券的 IM / MM / FM 系数各不相同，具体系数以平台公示为准。</p><p>各证券保证金系数请以平台实时公示为准，不同市场、不同标的系数存在差异。</p><h2 id="关键指标定义" tabindex="-1">关键指标定义 <a class="header-anchor" href="#关键指标定义" aria-label="Permalink to &quot;关键指标定义&quot;">​</a></h2><p>股权资产 = 现金余额 + 投资组合总市值</p><p>可用资金（含融资）= 股权资产 - 初始保证金要求 - 冻结资金</p><p>最大购买力 = 可用资金 ÷ 初始保证金系数（IM Ratio）</p><h2 id="示例说明" tabindex="-1">示例说明 <a class="header-anchor" href="#示例说明" aria-label="Permalink to &quot;示例说明&quot;">​</a></h2><p>存入现金 $10,000，账户融资额度 $20,000，目标标的 IM 系数为 30%：</p><p>可用资金 = $10,000 - $0（当前无持仓，IM 要求为 0）- $0 = $10,000</p><p>理论最大购买力 = $10,000 ÷ 30% ≈ $33,333</p><p>但实际受融资额度限制，最多融资 $20,000，因此实际最大购买力 = $10,000 + $20,000 = $30,000</p><p>购买后融资结欠 = $20,000，未超过融资额度上限，符合要求。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/margin/追缴保证金规则">追缴保证金规则</a> — 追缴触发条件、处理期限与强制平仓说明</li><li><a href="/margin/账户风控状态">账户风控状态</a> — 安全/预警/危险四级风控状态与购买力影响</li></ul>',28)])])}const u=e(i,[["render",o]]);export{m as __pageData,u as default};
